  async getManagerChain(employeeDomainId, myAuthToken = null) {
    try {
      // Get the employee's CIAM record to extract hierarchy IDs
      const userResponse = await this.getUserByDomainId([employeeDomainId], myAuthToken);
      if (!userResponse || userResponse.isError) {
        return null;
      }
      const user = Array.isArray(userResponse.value) ? userResponse.value[0] : null;
      if (!user) return null;

      // Build chain from the employee's CIAM record fields
      const chain = [];

      // Level 1: Section Manager (direct manager)
      if (user.departmentManagerUserDomain) {
        chain.push({
          level: 'section',
          domainId: user.departmentManagerUserDomain,
          nameEn: user.departmentManagerUserDomain,
          nameAr: user.departmentManagerUserDomain,
        });
      }

      // Level 2: Department Manager
      if (user.sectorManagerUserDomain) {
        chain.push({
          level: 'department',
          domainId: user.sectorManagerUserDomain,
          nameEn: user.sectorManagerUserDomain,
          nameAr: user.sectorManagerUserDomain,
        });
      }

      return chain.length > 0 ? chain : null;
    } catch (error) {
      console.error('[CIAM] Error in getManagerChain:', error.message);
      return null;
    }
  }

